@dataclass
class RemediationPlan:
    metric_id: str
    gap_description: str
    interventions: list[str]    # specific actions with owners and dates
    budget_required: float      # additional £ needed
    expected_recovery_weeks: int
    sponsor_approval_required: bool
    approved_by: str = ""
    approval_date: date = None

    def is_approved(self) -> bool:
        return bool(self.approved_by and self.approval_date)

    def validate(self) -> list[str]:
        errors = []
        if self.sponsor_approval_required and not self.is_approved():
            errors.append("Remediation plan requires sponsor approval before execution")
        if not self.interventions:
            errors.append("At least one intervention with owner and date is required")
        return errors
